const body = $input.first().json;
const sha = body.sha;
const content = JSON.parse(Buffer.from(body.content, 'base64').toString('utf-8'));
return content.map(c => ({ json: { ...c, _sha: sha } }));

const nome = $json.nome;
const q = encodeURIComponent(`${nome} concurso edital 2026`);
return { json: { ...$json, _query: q } };

const xml = $input.item.json.data || $input.item.json;
const text = typeof xml === 'string' ? xml : JSON.stringify(xml);
const titles = [...text.matchAll(/<title>(.*?)<\/title>/g)].map(m => m[1]).slice(1, 6);
return { json: { ...$('Montar busca').item.json, _manchetes: titles.join(' | ') || 'nenhuma notícia encontrada' } };

