const prev = $('Extrair manchetes').item.json;
let parsed;
try {
  const text = $json.content[0].text;
  parsed = JSON.parse(text);
} catch(e) {
  parsed = { status: prev.status, confianca: 'baixa', justificativa: 'falha ao interpretar resposta do modelo' };
}
const mudou = parsed.status !== prev.status && parsed.confianca === 'alta';
return { json: {
  nome: prev.nome, orgao: prev.orgao, nivel: prev.nivel, _sha: prev._sha,
  statusAtual: prev.status,
  status: mudou ? parsed.status : prev.status,
  confianca: parsed.confianca,
  justificativa: parsed.justificativa,
  mudou
} };

const items = $input.all().map(i => i.json);
const sha = items[0]?._sha;
const mudancas = items.filter(i => i.mudou);
const novaLista = items.map(({nome, orgao, nivel, status}) => ({nome, orgao, nivel, status}));
return { json: {
  temMudancas: mudancas.length > 0,
  sha,
  novaLista,
  changelog: mudancas.map(m => `${m.nome}: ${m.statusAtual} → ${m.status} (${m.justificativa})`).join('\n')
} };

